UPDATE public.questions SET
  question_text = 'In the $xy$-plane, line $l$ passes through points $(2,4)$ and $(6,-8)$. What is the slope of line $l$?',
  stimulus_text = NULL,
  options = '[{"id":"A","text":"-3","is_correct":true,"explanation":"Correct (A). Matches the worked solution above."},{"id":"B","text":"-2","is_correct":false,"explanation":"Choice B (-2…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"C","text":"2","is_correct":false,"explanation":"Choice C (2…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"D","text":"3","is_correct":false,"explanation":"Choice D (3…) reflects a common misread or arithmetic slip — re-check each operation against the question."}]'::jsonb,
  correct_answer = 'A',
  explanation = '**Step 1 — Understand the problem.** In the $xy$-plane, line $l$ passes through points $(2,4)$ and $(6,-8)$. What is the slope of line $l$?

**Step 2 — Solve.** The slope of a line passing through two points can be found using the formula: $m = \frac{y_2 - y_1}{x_2 - x_1}$. Substituting the coordinates (2, 4) and (6, -8) for $(x_1, y_1)$ and $(x_2, y_2)$, respectively, yields $m = \frac{-8 - 4}{6 - 2}$. Simplifying the expression gives $m = \frac{-12}{4}$, or $m = -3$. Therefore, the slope of line $l$ is $-3$.

**Step 3 — Select A.** -3

