UPDATE public.questions SET
  question_text = 'A circle with center $O$ has radius 5.  Points $A$ and $B$ lie on the circle such that the measure of minor arc $AB$ is $60^\circ$.  What is the area of sector $AOB$?',
  stimulus_text = NULL,
  options = '[{"id":"A","text":"$\\frac{25\\pi}{6}$","is_correct":true,"explanation":"Correct (A). Matches the worked solution above."},{"id":"B","text":"$\\frac{25\\pi}{3}$","is_correct":false,"explanation":"Choice B ($\\frac{25\\pi}{3}$…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"C","text":"$\\frac{125\\pi}{6}$","is_correct":false,"explanation":"Choice C ($\\frac{125\\pi}{6}$…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"D","text":"$\\frac{125\\pi}{3}$","is_correct":false,"explanation":"Choice D ($\\frac{125\\pi}{3}$…) reflects a common misread or arithmetic slip — re-check each operation against the question."}]'::jsonb,
  correct_answer = 'A',
  explanation = '**Step 1 — Understand the problem.** A circle with center $O$ has radius 5.  Points $A$ and $B$ lie on the circle such that the measure of minor arc $AB$ is $60^\circ$.  What is the area of sector $AOB$?

**Step 2 — Solve.** The area of a sector is proportional to the measure of its central angle.  Since the measure of minor arc AB is 60 degrees, the area of sector AOB is \frac{60}{360} = \frac{1}{6}$ the area of the circle. The area of the circle is $\pi r^2 = \pi (5)^2 = 25\pi$, so the area of sector AOB is \frac{1}{6} (25\pi) = \frac{25\pi}{6}$.

**Step 3 — Select A.** $\frac{25\pi}{6}$

