UPDATE public.questions SET
  question_text = 'A circle with center $O$ has a radius of 10.  Point $A$ lies on the circle, and the measure of central angle $\angle AOB$ is $60^\circ$.  What is the area of sector $AOB$?',
  stimulus_text = NULL,
  options = '[{"id":"A","text":"$10 \\pi$","is_correct":false,"explanation":"Choice A ($10 \\pi$…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"B","text":"$20 \\pi$","is_correct":false,"explanation":"Choice B ($20 \\pi$…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"C","text":"$\\frac{50}{3} \\pi$","is_correct":false,"explanation":"Choice C ($\\frac{50}{3} \\pi$…) reflects a common misread or arithmetic slip — re-check each operation against the question."},{"id":"D","text":"$\\frac{100}{3} \\pi$","is_correct":true,"explanation":"Correct (D). Matches the worked solution above."}]'::jsonb,
  correct_answer = 'D',
  explanation = '**Step 1 — Understand the problem.** A circle with center $O$ has a radius of 10.  Point $A$ lies on the circle, and the measure of central angle $\angle AOB$ is $60^\circ$.  What is the area of sector $AOB$?

**Step 2 — Solve.** The area of a sector is a fraction of the area of the whole circle, equal to the measure of the central angle divided by 360 degrees.  In this case, the area of sector $AOB$ is $\frac{60^\circ}{360^\circ} = \frac{1}{6}$ of the area of the whole circle.  The area of the whole circle is $\pi r^2 = \pi (10)^2 = 100 \pi$, so the area of sector $AOB$ is $\frac{1}{6} \cdot 100 \pi = \frac{100}{3} \pi$.

**Step 3 — Select D.** $\frac{100}{3} \pi$

**Distractor analysis:**
