UPDATE public.questions SET
  question_text = 'A survey of 100 students was conducted to determine their favorite subjects. The results showed that 40 students liked math, 50 students liked science, and 20 students liked both math and science. How many students did *not* like either math or science?',
  stimulus_text = NULL,
